customCss:
.site-header {
    height: 56px;
    padding: 0;
    display: flex;
    align-items: center;
    justify-content: space-between;
    width: 100%;
    margin: 0 auto;
    box-shadow: inset 0px -1px 0px #fafafa;
}
.site-header .left {
    display: flex;
}
.site-header .right {
    display: flex;
}
.site-header .avatar {
    margin: 0 10px 0 30px;
    border-radius: 50%;
    width: 32px;
    height: 32px;
}
.site-header .site-title {
    font-size: 24px;
}
.post-container .post .post-title,
.post-container .post .post-abstract {
    padding: 6px 0;
    font-weight: 500;
}
.post-container .post,
.post-container .post .post-info {
    padding-bottom: 6px;
}
.pagination-container {
    padding: 12px 16px;
}
